  ('retired-7ec62a85-moex-00353', 'retired-7ec62a85', 'retired-7ec62a85-moex-110-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '關於訴願法之敘述，下列何者錯誤？', '["處分機關未告知救濟期間，致相對人遲誤者，如自處分書送達後1年內聲明不服時，視為於法 定期間內所為", "提起訴願逾法定期間者，應為不受理之決定", "訴願人誤向訴願管轄機關以外之機關作不服原行政處分之表示者，應為不受理之決定", "訴願之提起，應自行政處分達到或公告期滿之次日起30日內為之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:27+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "137", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00354', 'retired-7ec62a85', 'retired-7ec62a85-moex-110-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '有關行政自我拘束原則之敘述，下列何者為錯誤？', '["得自平等原則導出", "只要有行政慣例之存在，即有行政自我拘束原則之適用", "行政機關適用構成要件用語明確之羈束條款時，不適用之", "行政機關有正當理由時，得為與行政先例不一致之決定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:27+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "137", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00355', 'retired-7ec62a85', 'retired-7ec62a85-moex-110-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '關於行政法院對於行政處分之審查，下列敘述何者錯誤？', '["對於具有高度屬人性之評定，得審查是否出於錯誤之事實認定", "對於具有高度屬人性之評定，採取較低密度之審查", "對於具有高度屬人性之評定，得審查作成程序之合法性", "對於具有高度屬人性之評定，得審查其合法性與妥當性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:27+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "137", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00356', 'retired-7ec62a85', 'retired-7ec62a85-moex-110-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '關於國家賠償法，下列敘述何者正確？', '["國家負損害賠償責任者，以回復原狀為原則", "賠償請求權之消滅時效期間，自請求權人實際知悉賠償義務機關時起算", "因公共設施之管理有欠缺所生之國家賠償責任，以管理機關有過失為必要", "於請求損害賠償時，法院得依聲請為假處分，命賠償義務機關暫先支付醫療費"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:27+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "137", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00357', 'retired-7ec62a85', 'retired-7ec62a85-moex-110-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '依我國釋憲實務，關於土地徵收與徵收補償費之敘述，下列何者錯誤？', '["徵收之目的不限於公用", "補償必須相當，且應儘速發給，否則徵收土地核准案即應失其效力", "土地所有權人因公路穿越其土地之地下，亦得請求徵收地上權", "徵收補償應等同於損害賠償，以填補所受損害及所失利益為範圍"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:27+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "137", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7fec267e-moex-00001', 'retired-7fec267e', 'retired-7fec267e-moex-114-adc7838e', 'sub-retired-7fec267e-01', NULL, 'essay', '在民主政治中，利益團體（interest groups）經常對公共議題進行政策倡
